  ('dietitian-moex-00847', 'dietitian', 'dietitian-moex-112-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據連鎖飲料便利商店及速食業之現場調製飲料標示規定，含果蔬汁但含量未達多少者，品名應 標示為「○○飲料」或等同意義字樣？', '["5%", "10%", "15%", "20%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:52+00:00", "source_pdf_sha1": "1bd37038064e", "answer_pdf_sha1": "916acd229a9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
