時應注意的原則。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:52+00:00", "source_pdf_sha1": "64a0998d3983", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
